import React, { useContext, useEffect, useRef, useState } from 'react';
import { QuestionContext } from './QuestionContext';
import { buildApiUrl } from './config';

function ImageCropper({ dataUrl, onCrop }) {
  const canvasRef = useRef(null);
  const imgRef = useRef(null);
  const [rect, setRect] = useState(null);
  const dragging = useRef(false);
  const start = useRef([0, 0]);

  useEffect(() => {
    const img = new Image();
    img.src = dataUrl;
    img.onload = () => {
      imgRef.current = img;
      const canvas = canvasRef.current;
      canvas.width = img.width;
      canvas.height = img.height;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(img, 0, 0);
    };
  }, [dataUrl]);

  const redraw = () => {
    const img = imgRef.current;
    const canvas = canvasRef.current;
    if (!img || !canvas) return;
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.drawImage(img, 0, 0);
    if (rect) {
      ctx.strokeStyle = 'red';
      ctx.lineWidth = 2;
      ctx.strokeRect(rect.x, rect.y, rect.w, rect.h);
    }
  };

  useEffect(redraw, [rect]);

  const onDown = (e) => {
    const canvas = canvasRef.current;
    const rectCanvas = canvas.getBoundingClientRect();
    const x = e.clientX - rectCanvas.left;
    const y = e.clientY - rectCanvas.top;
    start.current = [x, y];
    dragging.current = true;
    setRect({ x, y, w: 0, h: 0 });
  };

  const onMove = (e) => {
    if (!dragging.current) return;
    const canvas = canvasRef.current;
    const rectCanvas = canvas.getBoundingClientRect();
    const x = e.clientX - rectCanvas.left;
    const y = e.clientY - rectCanvas.top;
    const sx = start.current[0];
    const sy = start.current[1];
    setRect({ x: Math.min(sx, x), y: Math.min(sy, y), w: Math.abs(x - sx), h: Math.abs(y - sy) });
  };

  const onUp = () => {
    dragging.current = false;
  };

  const handleCrop = () => {
    if (!rect) return;
    const canvas = document.createElement('canvas');
    canvas.width = rect.w;
    canvas.height = rect.h;
    const ctx = canvas.getContext('2d');
    ctx.drawImage(imgRef.current, rect.x, rect.y, rect.w, rect.h, 0, 0, rect.w, rect.h);
    canvas.toBlob((blob) => {
      const croppedUrl = URL.createObjectURL(blob);
      onCrop(blob, croppedUrl);
    }, 'image/png');
  };

  return (
    <div>
      <canvas
        ref={canvasRef}
        style={{ border: '1px solid #ccc', maxWidth: '100%' }}
        onMouseDown={onDown}
        onMouseMove={onMove}
        onMouseUp={onUp}
      />
      <div style={{ marginTop: 8 }}>
        <button type="button" onClick={handleCrop}>Crop Selection</button>
      </div>
    </div>
  );
}

export default function QuestionUploader({ onSetExtractedText }) {
  const { questions, addOrUpdateQuestion, getQuestion } = useContext(QuestionContext);
  const [selectedQ, setSelectedQ] = useState('');
  const [files, setFiles] = useState([]);
  const [currentPreview, setCurrentPreview] = useState(null);
  const [message, setMessage] = useState('');

  const formatScore = (value) => `${Math.round((Number(value) || 0) * 100)}%`;

  useEffect(() => {
    if (questions.length > 0 && !selectedQ) setSelectedQ(questions[0].questionNumber);
  }, [questions, selectedQ]);

  useEffect(() => {
    if (!selectedQ) return;
    const question = getQuestion(selectedQ);
    if (question && question.ocrText) {
      onSetExtractedText(question.ocrText);
    }
  }, [selectedQ, getQuestion, onSetExtractedText]);

  const handleFiles = (e) => {
    const list = Array.from(e.target.files || []);
    list.forEach((file) => {
      const reader = new FileReader();
      reader.onload = () => setFiles((current) => [...current, { name: file.name, dataUrl: reader.result }]);
      reader.readAsDataURL(file);
    });
  };

  const dataUrlToBlob = async (dataUrl) => {
    const response = await fetch(dataUrl);
    return response.blob();
  };

  const extractTextFromDataUrl = async (dataUrl, fileName = 'upload.png') => {
    const blob = await dataUrlToBlob(dataUrl);
    const formData = new FormData();
    formData.append('file', blob, fileName);

    const uploadResponse = await fetch(buildApiUrl('/ocr'), { method: 'POST', body: formData });
    const uploadData = await uploadResponse.json();
    const ocrDataUrl = uploadData.data_url;

    if (!window.puter) {
      throw new Error('Puter not loaded');
    }

    return window.puter.ai.chat(
      'Extract all the text from this image and return it as a paragraph. Only return the text, nothing else.',
      ocrDataUrl,
      { model: 'gpt-5-nano' }
    );
  };

  const evaluateSubjectiveAnswer = async (question, studentAnswer) => {
    const response = await fetch(buildApiUrl('/evaluate-subjective'), {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        questionNumber: question.questionNumber,
        questionType: question.questionType,
        questionText: question.questionText || '',
        answerKey: question.answerKey || '',
        studentAnswer,
        maxMarks: question.maxMarks || 10,
      }),
    });

    const result = await response.json();
    if (!response.ok || result.error) {
      throw new Error(result.error || `Evaluation failed with status ${response.status}`);
    }

    return result;
  };

  const handleCropResult = (blob, croppedUrl) => {
    (async () => {
      setMessage('Processing cropped image...');
      try {
        const formData = new FormData();
        formData.append('file', blob, 'crop.png');
        const uploadResponse = await fetch(buildApiUrl('/ocr'), { method: 'POST', body: formData });
        const uploadData = await uploadResponse.json();

        if (!window.puter) {
          throw new Error('Puter not loaded');
        }

        const extracted = await window.puter.ai.chat(
          'Extract all the text from this image and return it as a paragraph. Only return the text, nothing else.',
          uploadData.data_url,
          { model: 'gpt-5-nano' }
        );

        const question = getQuestion(selectedQ) || {
          questionNumber: selectedQ,
          questionType: 'subjective',
          questionText: '',
          ocrText: '',
          uploads: []
        };

        question.ocrText = question.ocrText ? `${question.ocrText}\n${extracted}` : extracted;
        question.uploads = question.uploads || [];
        const uploadEntry = { id: Date.now(), name: 'crop.png', dataUrl: croppedUrl };
        question.uploads.push(uploadEntry);

        let evaluation = null;
        if (question.questionType === 'subjective') {
          evaluation = await evaluateSubjectiveAnswer(question, extracted);
        }

        question.lastEvaluation = evaluation
          ? {
              uploadId: uploadEntry.id,
              ...evaluation,
              extractedText: extracted,
            }
          : {
              uploadId: uploadEntry.id,
              marks: null,
              maxMarks: question.maxMarks || 10,
              justification: '',
              extractedText: extracted,
              similarityBreakdown: null,
            };

        addOrUpdateQuestion(question);
        onSetExtractedText(question.ocrText);
        setMessage(
          question.questionType === 'subjective'
            ? 'Cropped image processed and evaluated for the selected subjective question.'
            : 'Cropped image processed. ML evaluation is only available for subjective questions.'
        );
      } catch (e) {
        console.error(e);
        setMessage('Error processing image: ' + e.message);
      }
    })();
  };

  const handleSelectFileForCrop = (item) => {
    setCurrentPreview(item);
  };

  const handleEvaluateQuestion = async () => {
    if (!selectedQ) {
      setMessage('Select a question first');
      return;
    }

    const question = getQuestion(selectedQ);
    if (!question) {
      setMessage('Question not found');
      return;
    }

    if (question.questionType !== 'subjective') {
      setMessage('ML evaluation is only available for subjective questions.');
      return;
    }

    setMessage('Evaluating answer...');
    try {
      if (!question.ocrText || !question.ocrText.trim()) {
        if (!files.length) {
          setMessage('No extracted text found. Upload images or crop first.');
          return;
        }

        if (!window.puter) {
          throw new Error('Puter not loaded');
        }

        let combinedText = '';
        for (const file of files) {
          const extracted = await extractTextFromDataUrl(file.dataUrl, file.name || 'upload.png');
          combinedText += combinedText ? `\n${extracted}` : extracted;
        }

        question.ocrText = combinedText;
        addOrUpdateQuestion(question);
        onSetExtractedText(combinedText);
      }

      const evaluation = await evaluateSubjectiveAnswer(question, question.ocrText);
      question.lastEvaluation = {
        uploadId: question.uploads && question.uploads.length ? question.uploads[question.uploads.length - 1].id : Date.now(),
        ...evaluation,
        extractedText: question.ocrText,
      };

      addOrUpdateQuestion(question);
      setMessage('Subjective answer evaluation complete. Review the similarity metrics below.');
    } catch (e) {
      console.error(e);
      setMessage('Evaluation failed: ' + (e.message || e));
    }
  };

  return (
    <div style={{ padding: 12 }}>
      <h3>Question Uploader</h3>
      <div style={{ marginBottom: 8 }}>
        <label>Select Question</label>
        <select value={selectedQ} onChange={(e) => setSelectedQ(e.target.value)}>
          <option value="">-- select --</option>
          {questions.map((question) => (
            <option key={question.questionNumber} value={question.questionNumber}>
              {question.questionNumber} - {question.questionText.slice(0, 40)}
            </option>
          ))}
        </select>
      </div>

      <div style={{ marginBottom: 8 }}>
        <label>Upload images for selected question (multiple)</label>
        <input type="file" accept="image/*" multiple onChange={handleFiles} />
        <div style={{ marginTop: 8 }}>
          <button type="button" onClick={handleEvaluateQuestion} disabled={!selectedQ}>
            Evaluate Subjective Answer
          </button>
        </div>
      </div>

      <div style={{ display: 'flex', gap: 12 }}>
        <div style={{ flex: 1 }}>
          <h4>Uploaded images</h4>
          {files.map((file, index) => (
            <div key={index} style={{ marginBottom: 8 }}>
              <img src={file.dataUrl} alt={file.name} style={{ maxWidth: 150 }} />
              <div>
                <button onClick={() => handleSelectFileForCrop(file)}>Crop</button>
              </div>
            </div>
          ))}
        </div>

        <div style={{ flex: 2 }}>
          <h4>Crop / Preview</h4>
          {currentPreview ? (
            <>
              <ImageCropper dataUrl={currentPreview.dataUrl} onCrop={handleCropResult} />
              {selectedQ && (() => {
                const question = getQuestion(selectedQ);
                if (!question || !question.lastEvaluation) return null;
                const evaluation = question.lastEvaluation;

                return (
                  <div style={{ marginTop: 12, border: '1px solid #ddd', padding: 8 }}>
                    <div>
                      <strong>Marks:</strong>{' '}
                      <input type="number" defaultValue={evaluation.marks ?? ''} id={`marks-${evaluation.uploadId}`} style={{ width: 80 }} />
                    </div>
                    <div style={{ marginTop: 8 }}>
                      <strong>Justification:</strong>
                      <div>
                        <textarea id={`just-${evaluation.uploadId}`} defaultValue={evaluation.justification} style={{ width: '100%', minHeight: 60 }} />
                      </div>
                    </div>
                    <div style={{ marginTop: 8 }}>
                      <button onClick={async () => {
                        const input = document.getElementById(`marks-${evaluation.uploadId}`);
                        const corrected = parseFloat(input.value);
                        if (isNaN(corrected)) {
                          setMessage('Please enter a numeric mark');
                          return;
                        }

                        try {
                          const questionToUpdate = getQuestion(selectedQ);
                          const previousMarks = questionToUpdate.lastEvaluation.marks;
                          questionToUpdate.lastEvaluation.marks = corrected;
                          addOrUpdateQuestion(questionToUpdate);

                          await fetch(buildApiUrl('/feedback'), {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json' },
                            body: JSON.stringify({
                              questionNumber: selectedQ,
                              uploadId: evaluation.uploadId,
                              previousMarks,
                              correctedMarks: corrected,
                              maxMarks: evaluation.maxMarks || questionToUpdate.maxMarks || 10,
                              justification: document.getElementById(`just-${evaluation.uploadId}`)?.value || evaluation.justification || '',
                              extractedText: evaluation.extractedText || ''
                            })
                          });

                          setMessage('Mark updated and feedback stored for later calibration.');
                        } catch (e) {
                          console.error(e);
                          setMessage('Failed to send feedback: ' + e.message);
                        }
                      }}>
                        Save corrected mark
                      </button>
                    </div>
                  </div>
                );
              })()}
            </>
          ) : (
            <div>Select an image to crop</div>
          )}

          {selectedQ && (() => {
            const question = getQuestion(selectedQ);
            if (!question || !question.lastEvaluation) return null;
            const evaluation = question.lastEvaluation;

            return (
              <div style={{ marginTop: 12, border: '1px solid #ccc', padding: 8 }}>
                <h4>Latest Evaluation</h4>
                <div><strong>Marks:</strong> {evaluation.marks ?? '—'} / {evaluation.maxMarks}</div>
                {evaluation.method && <div style={{ marginTop: 8 }}><strong>Method:</strong> {evaluation.method}</div>}
                {typeof evaluation.confidenceScore === 'number' && (
                  <div style={{ marginTop: 8 }}><strong>Confidence:</strong> {formatScore(evaluation.confidenceScore)}</div>
                )}
                <div style={{ marginTop: 8 }}>
                  <strong>Justification:</strong>
                  <div style={{ border: '1px solid #eee', padding: 8 }}>{evaluation.justification || '—'}</div>
                </div>
                {evaluation.similarityBreakdown && (
                  <div style={{ marginTop: 8 }}>
                    <strong>Similarity Breakdown:</strong>
                    <ul style={{ marginTop: 6, paddingLeft: 20 }}>
                      <li>TF-IDF cosine similarity: {formatScore(evaluation.similarityBreakdown.cosineSimilarity)}</li>
                      <li>Character similarity: {formatScore(evaluation.similarityBreakdown.characterSimilarity)}</li>
                      <li>Jaccard similarity: {formatScore(evaluation.similarityBreakdown.jaccardSimilarity)}</li>
                      <li>Keyword coverage: {formatScore(evaluation.similarityBreakdown.keywordCoverage)}</li>
                      <li>Sentence coverage: {formatScore(evaluation.similarityBreakdown.sentenceCoverage)}</li>
                      <li>Length adequacy: {formatScore(evaluation.similarityBreakdown.lengthAdequacy)}</li>
                      <li>Feedback similarity: {formatScore(evaluation.similarityBreakdown.feedbackSimilarity)}</li>
                    </ul>
                  </div>
                )}
                {Array.isArray(evaluation.matchedKeywords) && evaluation.matchedKeywords.length > 0 && (
                  <div style={{ marginTop: 8 }}><strong>Matched keywords:</strong> {evaluation.matchedKeywords.join(', ')}</div>
                )}
                {Array.isArray(evaluation.missingKeywords) && evaluation.missingKeywords.length > 0 && (
                  <div style={{ marginTop: 8 }}><strong>Missing keywords:</strong> {evaluation.missingKeywords.join(', ')}</div>
                )}
                {evaluation.calibrationApplied && (
                  <div style={{ marginTop: 8 }}>
                    <strong>Feedback calibration:</strong> Applied using {evaluation.feedbackSamplesUsed} similar checked answers.
                  </div>
                )}
                <div style={{ marginTop: 8 }}>
                  <button onClick={handleEvaluateQuestion}>Re-evaluate</button>
                </div>
              </div>
            );
          })()}

          {message && <div style={{ marginTop: 8 }}>{message}</div>}
        </div>
      </div>
    </div>
  );
}
